\title{\bf TUni: Absolute Time, Multiplicative Time Factors, and the Dissolution of Quantum Paradoxes}
\author{J\"org Geisbauer}
\date{August 2025}

\begin{document}
\maketitle

\paragraph{Axioms (TUni).}
(i) There exists an \emph{absolute present} $T$.
(ii) Each physical channel $i$ carries a \emph{time measure} $f_i=\cos\zeta_i\in(0,1]$, where $\zeta_i$ is a \emph{measure angle} (not a projection).
(iii) Local proper time flow is multiplicative across channels.

\section*{1. Master Time Law and Covariant Channels}
\textbf{Channel measures}
\begin{align}
f_i &= \cos\zeta_i \in (0,1], \label{eq:fi}\\[2mm]
F &\equiv \prod_i f_i, 
\qquad 
D \equiv -\sum_i \ln f_i,
\qquad 
F = e^{-D}, \label{eq:F-D}
\end{align}
\textbf{Proper time flow}
\begin{equation}
\frac{d\tau}{dt} \;=\; F. \label{eq:flow}
\end{equation}
\textbf{Gravitation (covariant)} \quad for any static metric,
\begin{equation}
f_{\rm grav} \;=\; \sqrt{-g_{tt}}, 
\qquad \text{(Schwarzschild: } f_{\rm grav}=\sqrt{1-\tfrac{2GM}{rc^2}}\text{)}. \label{eq:gtt}
\end{equation}
\textbf{Kinematics (SR)} \quad $f_{\rm kin}=\sqrt{1-\tfrac{v^2}{c^2}}$. \hfill
\textbf{Expansion (FRW)} \quad $f_{\rm exp}=\tfrac{1}{1+z}$. \hfill
\textbf{Quantum/Planck limit} \quad $f_{\rm quant}=\sqrt{1-\left(\tfrac{E}{E_{\rm Pl}}\right)^2}$.

\section*{2. Absolute-Now Decomposition}
Define the \emph{global angle} by
\begin{equation}
\cos\Theta \;:=\; \prod_i f_i \;=\; F. \label{eq:Theta}
\end{equation}
Then the TUni splitting of a reference interval $T_0$ reads
\begin{equation}
\frac{T_{\rm present}}{T_0}=\cos^2\Theta, 
\qquad 
\frac{T_{\rm hidden}}{T_0}=\sin^2\Theta,
\qquad 
\cos^2\Theta+\sin^2\Theta=1. \label{eq:cos2-sin2}
\end{equation}
No paradox arises: the present/hidden partition is fixed by $\Theta$.

\section*{3. Third-Observer Reconstruction (Consensus Time)}
For channels with local stamps $t_i'$, weights $w_i$, latency $\Delta t_i$ and horizon $\Delta\tau_i$:
\begin{align}
T_{\rm past}   &= \frac{\sum_i w_i\, f_i\, (t_i'-\Delta t_i)}{\sum_i w_i}, \label{eq:Tp}\\
T_{\rm future} &= \frac{\sum_i w_i\, f_{i,\rm fut}^{\,2}\, (t_i'+\Delta\tau_i)\, e^{-\beta H_0 t_i'}}{\sum_i w_i}, \label{eq:Tf}\\
T_{\rm present}&= \tfrac{1}{2}\,(T_{\rm past}+T_{\rm future}). \label{eq:Tpres}
\end{align}
This reconstructs the absolute simultaneity $T$ from distorted views.

\section*{4. Cosmic Coach (DM/DE) --- Explicit and Testable}
Let the \emph{cosmic coach} modulate $F$ at large scales:
\begin{equation}
f_{\rm cosmos}(T) 
= \exp\!\Big[-\,\alpha\,\frac{G\hbar}{c^5}\,(\rho_{\rm DM}+\rho_{\rm DE})\,T^2\Big],
\qquad \alpha\sim\mathcal{O}(1). \label{eq:coach}
\end{equation}
Then $F \to F\cdot f_{\rm cosmos}$ in \eqref{eq:flow}. 
Prediction: small but systematic clock-rate drifts in DM-dense regions and at high $z$.

\section*{5. Paradoxes Dissolved (Equations, not Rhetoric)}
\textbf{(a) Schr\"odinger cat:} the wavefunction is epistemic. In $T$,
\begin{equation}
\text{Cat}(T)\in\{\text{alive},\text{dead}\} \quad\text{(never a physical mixture)}.
\end{equation}
\textbf{(b) Entanglement:} outcomes are functions of the same $T$; no signalling:
\begin{equation}
\frac{\partial}{\partial b}\,\langle A(a,T)\rangle \;=\; 0, 
\qquad 
\frac{\partial}{\partial a}\,\langle B(b,T)\rangle \;=\; 0. 
\end{equation}
\textbf{(c) Double-slit:} observed intensity is the \emph{sum} of single-slit patterns.
Let slit half-width $b$, separation $d$, screen distance $L$, wavelength $\lambda$, and $k=\tfrac{2\pi}{\lambda}$. With $\operatorname{sinc}x\!=\!\frac{\sin x}{x}$,
\begin{align}
I_1(x) &= I_0\,\operatorname{sinc}^2\!\Big(\frac{\pi b x}{\lambda L}\Big),\quad
I_2(x) = I_0\,\operatorname{sinc}^2\!\Big(\frac{\pi b (x-\tfrac{dL}{L})}{\lambda L}\Big),\\
I(x)   &= I_1(x)+I_2(x).
\end{align}
\textit{Nulls} occur when single-slit zeros align; no self-interference is required.
\textbf{(d) Quantum eraser:} all events share $T$; ``retrocausality'' is post-sorting of data, not dynamics.

\section*{6. Falsifiable Signatures (Do or Refute)}
\begin{itemize}
\item \textbf{GNSS/LEO clocks:} compute $\Delta\tau/\tau$ with \eqref{eq:flow} using $f_{\rm grav}=\sqrt{-g_{tt}}$ and $f_{\rm kin}$; look for residuals consistent with $f_{\rm exp}$ at low $z$.
\item \textbf{Cluster clocks:} pulsar timing in DM halos should show a tiny systematic drift if $f_{\rm cosmos}$ \eqref{eq:coach} is nontrivial.
\item \textbf{High-$z$ SNe:} a small TUni-bias in distance moduli at $z\!\gtrsim\!1$ if $f_{\rm exp}$ enters multiplicatively.
\item \textbf{Double-slit scans:} map $(b,d,\lambda,L)$ and verify $I(x)=I_1+I_2$ with \emph{nonzero} minima except at geometric alignments.
\end{itemize}

\paragraph{Master box.}
\begin{equation}
\boxed{\;\frac{d\tau}{dt} \;=\; 
\big(\sqrt{-g_{tt}}\big)\cdot\sqrt{1-\tfrac{v^2}{c^2}}\cdot \frac{1}{1+z}\cdot
\sqrt{1-\big(\tfrac{E}{E_{\rm Pl}}\big)^2}\cdot f_{\rm cosmos}(T)\;
}
\end{equation}

